@app.route('/genres')
def genres():
    genres = load_genres()
    songs = load_songs()
    artists = load_artists()

    selected_genre = request.args.get('genre', '')

    genre_songs = []
    genre_artists = []

    if selected_genre:
        selected_genre_lower = selected_genre.lower()

        # Find genre by name
        genre_obj = next((g for g in genres if g['genre_name'].lower() == selected_genre_lower), None)

        if genre_obj:
            for s in songs:
                if s['genre'].lower() == selected_genre_lower:
                    artist_name = get_artist_name(s['artist_id'], artists)
                    genre_songs.append({
                        'song_id': s['song_id'],
                        'title': s['title'],
                        'artist_name': artist_name
                    })
            for a in artists:
                if a['genre'].lower() == selected_genre_lower:
                    genre_artists.append({'artist_id': a['artist_id'], 'name': a['name']})
        else:
            # Invalid genre selected
            genre_songs = []
            genre_artists = []

    return render_template('genres.html', genres=genres, selected_genre=selected_genre, genre_songs=genre_songs, genre_artists=genre_artists)

